341	// displayStalenessHints shows soft hints when project skills or plugins are outdated.
342	func (f *CommandFactory) displayStalenessHints(cmd *cobra.Command) {
343		// Skip for machine-readable output
344		if jsonFlag, _ := cmd.Flags().GetBool("json"); jsonFlag {
345			return
346		}
347		if silentFlag, _ := cmd.Flags().GetBool("silent"); silentFlag {
348			return
349		}
350		// Skip when stdout is not a terminal (pipes, scripts, CI)
351		if !isatty.IsTerminal(os.Stdout.Fd()) && !isatty.IsCygwinTerminal(os.Stdout.Fd()) {
352			return
353		}
354	
355		// Dev builds don't hint
356		if f.Version == "" || f.Version == "dev" {
357			return
358		}
359	
360		// Check project staleness
361		projectVersion := readProjectVersions(f.WorkingDir)
362		if projectVersion != "" && projectVersion != "dev" {
363			// Is the binary newer than the project?
364			projectNeedsUpgrade, err := update.NeedsUpgrade(projectVersion, f.Version)
365			if err == nil && projectNeedsUpgrade {
366				_, _ = fmt.Fprintf(cmd.OutOrStdout(),
367					"\n💡 Project skills from DDx v%s (you have %s). Run 'ddx init --force' to update.\n",
368					strings.TrimPrefix(projectVersion, "v"),
369					f.Version)
370			}
371		}
372	
373		// Check plugin staleness (reuse ddx outdated logic)
374		f.displayPluginStalenessHints(cmd)
375	}
