157	func (f *CommandFactory) runMetricShowCommand(cmd *cobra.Command, args []string) error {
158		def, doc, err := f.metricStore().Validate(args[0])
159		if err != nil {
160			return err
161		}
162		history, err := f.metricHistory(args[0])
163		if err != nil {
164			return err
165		}
166		recent := history
167		if len(recent) > 5 {
168			recent = recent[len(recent)-5:]
169		}
170		if cmd.Flags().Changed("json") {
171			enc := json.NewEncoder(cmd.OutOrStdout())
172			enc.SetIndent("", "  ")
173			return enc.Encode(map[string]any{
174				"artifact":       doc,
175				"definition":     def,
176				"recent_history": recent,
177			})
178		}
179		fmt.Fprintf(cmd.OutOrStdout(), "ID:        %s\n", doc.ID)
180		if doc.Title != "" {
181			fmt.Fprintf(cmd.OutOrStdout(), "Title:     %s\n", doc.Title)
182		}
183		fmt.Fprintf(cmd.OutOrStdout(), "Path:      %s\n", doc.Path)
184		fmt.Fprintf(cmd.OutOrStdout(), "Definition: %s\n", def.DefinitionID)
185		fmt.Fprintf(cmd.OutOrStdout(), "Command:   %s\n", joinCommand(def.Command))
186		fmt.Fprintf(cmd.OutOrStdout(), "Created:   %s\n", def.CreatedAt.Format(time.RFC3339))
187		fmt.Fprintln(cmd.OutOrStdout(), "Recent history:")
188		if len(recent) == 0 {
189			fmt.Fprintln(cmd.OutOrStdout(), "  (none)")
190			return nil
191		}
192		for _, rec := range recent {
193			fmt.Fprintf(cmd.OutOrStdout(), "  %s  %s  %.3f%s  %s\n", rec.ObservedAt.Format(time.RFC3339), rec.RunID, rec.Value, rec.Unit, rec.Status)
194		}
195		return nil
196	}
