     5	func metricDefinitionFromExec(def ddxexec.Definition) (Definition, error) {
     6		out := Definition{
     7			DefinitionID: def.ID,
     8			MetricID:     metricArtifactID(def.ArtifactIDs),
     9			Command:      append([]string{}, def.Executor.Command...),
    10			Cwd:          def.Executor.Cwd,
    11			Env:          cloneStringMap(def.Executor.Env),
    12			Thresholds: Thresholds{
    13				Warn:    def.Evaluation.Thresholds.WarnMS,
    14				Ratchet: def.Evaluation.Thresholds.RatchetMS,
    15				Unit:    "",
    16			},
    17			Comparison: def.Evaluation.Comparison,
    18			Active:     def.Active,
    19			CreatedAt:  def.CreatedAt,
    20		}
    21		if def.Result.Metric != nil {
    22			out.Thresholds.Unit = def.Result.Metric.Unit
    23		}
    24		return out, nil
    25	}
    26	
    27	func metricHistoryFromExec(rec ddxexec.RunRecord) (HistoryRecord, error) {
    28		out := HistoryRecord{
    29			RunID:        rec.RunID,
    30			MetricID:     metricArtifactID(rec.ArtifactIDs),
    31			DefinitionID: rec.DefinitionID,
    32			ObservedAt:   rec.StartedAt,
    33			Status:       StatusPass,
    34			ExitCode:     rec.ExitCode,
    35			DurationMS:   rec.FinishedAt.Sub(rec.StartedAt).Milliseconds(),
    36			Stdout:       rec.Result.Stdout,
    37			Stderr:       rec.Result.Stderr,
    38			ArtifactID:   metricArtifactID(rec.ArtifactIDs),
    39		}
    40		if rec.Status != ddxexec.StatusSuccess {
    41			out.Status = StatusFail
    42		}
    43		if rec.Result.Metric != nil {
    44			out.Value = rec.Result.Metric.Value
    45			out.Unit = rec.Result.Metric.Unit
    46			out.Comparison = ComparisonResult{
    47				Baseline:  rec.Result.Metric.Comparison.Baseline,
    48				Delta:     rec.Result.Metric.Comparison.Delta,
    49				Direction: rec.Result.Metric.Comparison.Direction,
    50			}
    51		}
    52		return out, nil
    53	}
    54	
    55	func cloneStringMap(in map[string]string) map[string]string {
    56		if len(in) == 0 {
    57			return nil
    58		}
    59		out := make(map[string]string, len(in))
    60		for k, v := range in {
    61			out[k] = v
    62		}
    63		return out
    64	}
    65	
    66	func metricArtifactID(ids []string) string {
    67		if len(ids) == 0 {
    68			return ""
    69		}
    70		for _, id := range ids {
    71			if len(id) >= 4 && id[:4] == "MET-" {
    72				return id
    73			}
    74		}
    75		return ids[0]
    76	}

