    85	func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
    86		history, err := s.History(metricID)
    87		if err != nil {
    88			return HistoryRecord{}, ComparisonResult{}, err
    89		}
    90		if len(history) == 0 {
    91			return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
    92		}
    93		current := history[len(history)-1]
    94		target, err := selectComparisonTarget(history, against)
    95		if err != nil {
    96			return HistoryRecord{}, ComparisonResult{}, err
    97		}
    98		result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
    99		current.Comparison = result
   100		return current, result, nil
   101	}
