   103	func (s *Store) Trend(metricID string) (TrendSummary, error) {
   104		history, err := s.History(metricID)
   105		if err != nil {
   106			return TrendSummary{}, err
   107		}
   108		if len(history) == 0 {
   109			return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
   110		}
   111		summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: history[len(history)-1].Unit, UpdatedAt: history[len(history)-1].ObservedAt}
   112		var sum float64
   113		for _, rec := range history {
   114			if rec.Value < summary.Min {
   115				summary.Min = rec.Value
   116			}
   117			if rec.Value > summary.Max {
   118				summary.Max = rec.Value
   119			}
   120			sum += rec.Value
   121			summary.UpdatedAt = rec.ObservedAt
   122			if rec.Unit != "" {
   123				summary.Unit = rec.Unit
   124			}
   125		}
   126		summary.Count = len(history)
   127		summary.Average = sum / float64(len(history))
   128		return summary, nil
   129	}
