   168	func (s *Store) History(metricID string) ([]HistoryRecord, error) {
   169		if s.execStore == nil {
   170			return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
   171		}
   172		records, err := s.execStore.History(metricID, "")
   173		if err != nil {
   174			return nil, err
   175		}
   176		out := make([]HistoryRecord, 0, len(records))
   177		for _, rec := range records {
   178			mapped, err := metricHistoryFromExec(rec)
   179			if err != nil {
   180				return nil, err
   181			}
   182			if mapped.MetricID == metricID {
   183				out = append(out, mapped)
   184			}
   185		}
   186		return out, nil
   187	}
