   189	func (s *Store) loadMetricArtifact(metricID string) (*docgraph.Document, error) {
   190		if !strings.HasPrefix(metricID, "MET-") {
   191			return nil, fmt.Errorf("%w: %s", errNotMetricArtifact, metricID)
   192		}
   193		graph, err := docgraph.BuildGraph(s.WorkingDir)
   194		if err != nil {
   195			return nil, err
   196		}
   197		doc, ok := graph.Show(metricID)
   198		if !ok {
   199			return nil, fmt.Errorf("metric artifact %q not found", metricID)
   200		}
   201		return &doc, nil
   202	}
   203	
   204	func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
   205		switch against {
   206		case "", "latest":
   207			return history[len(history)-1], nil
   208		case "baseline":
   209			return history[0], nil
   210		default:
   211			for _, rec := range history {
   212				if rec.RunID == against {
   213					return rec, nil
   214				}
   215			}
   216			return HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
   217		}
   218	}
   219	
   220	func comparisonFor(current, baseline float64, direction string) ComparisonResult {
   221		delta := current - baseline
   222		if direction == ComparisonHigherIsBetter {
   223			delta = baseline - current
   224		}
   225		return ComparisonResult{
   226			Baseline:  baseline,
   227			Delta:     delta,
   228			Direction: direction,
   229		}
   230	}

